47	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
48	
49	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
50	const COMPONENT_BLOCK_SIZE = 3;
51	const COMPONENT_BLOCK_PRICE = 60;
52	
53	const groupByType = (items: Item[]): Map<string, Item[]> => {
54	  const groups = new Map<string, Item[]>();
55	  for (const item of items) {
56	    const group = groups.get(item.type) ?? [];
57	    group.push(item);
58	    groups.set(item.type, group);
59	  }
60	  return groups;
61	};
62	
63	const isHighlyEnchanted = (item: Item): boolean =>
64	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
65	
66	const itemSurchargeFactor = (item: Item): number =>
67	  (item.cursed ? CURSE_SURCHARGE : 0) +
68	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
69	
70	const itemModifiersFor = (item: Item): number =>
71	  basePremiumFor(item) * itemSurchargeFactor(item);
72	
73	const groupBaseCost = (type: string, group: Item[]): number => {
74	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
75	    return COMPONENT_BLOCK_PRICE;
76	  }
77	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
78	};
79	
80	const policyBase = (items: Item[]): number => {
81	  let total = 0;
82	  for (const [type, group] of groupByType(items)) {
83	    total += groupBaseCost(type, group);
84	  }
85	  return total;
86	};
87	
88	const itemSurchargesTotal = (items: Item[]): number =>
89	  items.reduce((sum, item) => sum + itemModifiersFor(item), 0);
90	
91	const policyModifierFactor = (
92	  customer: { yearsWithMHPCO: number },
93	  isFollowUp: boolean,
94	): number =>
95	  FIRST_INSURANCE_SURCHARGE -
96	  (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 0) -
97	  (isFollowUp ? FOLLOW_UP_CONTRACT_DISCOUNT : 0);
98	
99	const quote = (
100	  items: Item[],
101	  customer: { yearsWithMHPCO: number },
102	  isFollowUp: boolean,
103	): QuoteResult => {
104	  const base = policyBase(items);
105	  const itemSurcharges = itemSurchargesTotal(items);
106	  const policyModifiers = base * policyModifierFactor(customer, isFollowUp);
107	  return {
108	    premium: Math.ceil(base + itemSurcharges + policyModifiers + PROCESSING_FEE),
109	  };
110	};
